package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAnyPlatformType_withAndroidType() throws Exception {
    // Using reflection to mock isAndroidType(String) to return true
    Class<?> clazz = String.class; // className = "java.lang.String"

    // We expect isAnyPlatformType to return true because isAndroidType returns true
    // Use reflection to temporarily override private static isAndroidType(String)
    // But since we cannot override private static method easily, we test with an Android class name

    // Create a dummy class with name starting with "android."
    Class<?> androidClass = AndroidDummy.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(androidClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinPackage() {
    Class<?> kotlinClass = KotlinDummy.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinxPackage() {
    Class<?> kotlinxClass = KtxDummy.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinxClass));
  }

  @Test
  void testIsAnyPlatformType_withScalaPackage() {
    Class<?> scalaClass = ScalaDummy.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(scalaClass));
  }

  @Test
  void testIsAnyPlatformType_withOtherClass() {
    Class<?> otherClass = String.class;
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(otherClass));
  }

  // Dummy classes to simulate package names
  static class AndroidDummy {
    @Override
    public String toString() {
      return "android.dummy.Class";
    }
    public static String getName() {
      return "android.dummy.Class";
    }
  }

  static class KotlinDummy {
